#include <chrono>
#include <cmath>
#include <cstdio>
#include <iostream>
#include <iomanip>
#include <limits>
#include <utility>
#include <omp.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N-1) {
        f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
      }
      else if (j == 0 || j == N-1) {
        f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
      }
      else {
        f[IDX(i,j)] = 0.0f;
      }
    }
  }
}

void jacobi_step(float* f, const float* f_old, float* error) {
  #pragma omp target parallel
  {
    float f_old_tile[18][18];

    int i = omp_get_thread_num() % N;
    int j = omp_get_thread_num() / N;

    int local_i = i % 16;
    int local_j = j % 16;

    f_old_tile[local_j+1][local_i+1] = f_old[IDX(i,j)];

    if (local_i == 0 && i >= 1) {
      f_old_tile[local_j+1][local_i+0] = f_old[IDX(i-1,j)];
    }
    if (local_i == 15 && i <= N-2) {
      f_old_tile[local_j+1][local_i+2] = f_old[IDX(i+1,j)];
    }
    if (local_j == 0 && j >= 1) {
      f_old_tile[local_j+0][local_i+1] = f_old[IDX(i,j-1)];
    }
    if (local_j == 15 && j <= N-2) {
      f_old_tile[local_j+2][local_i+1] = f_old[IDX(i,j+1)];
    }

    #pragma omp target barrier

    float err = 0.0f;

    if (j >= 1 && j <= N-2) {
      if (i >= 1 && i <= N-2) {
        f[IDX(i,j)] = 0.25f * (f_old_tile[local_j+1][local_i+2] + 
                               f_old_tile[local_j+1][local_i+0] + 
                               f_old_tile[local_j+2][local_i+1] + 
                               f_old_tile[local_j+0][local_i+1]);
        float df = f[IDX(i,j)] - f_old_tile[local_j+1][local_i+1];
        err = df * df;
      }
    }

    float reduction_array[16];
    #pragma omp target atomic write
    reduction_array[local_j] = err;

    #pragma omp target barrier

    if (local_j == 0) {
      err = reduction_array[local_i];
      #pragma omp target atomic read
      for (int k = 0; k < 16; k++) {
        if (k != local_i) {
          float tmp;
          #pragma omp target atomic read
          tmp = reduction_array[k];
          err += tmp;
        }
      }
      #pragma omp target atomic
      *error += err;
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* d_f;
  float* d_f_old;
  float* d_error;

  float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));

  initialize_data(f);
  initialize_data(f_old);

  d_f = (float*) malloc(N * N * sizeof(float));
  memcpy(d_f, f, N * N * sizeof(float));

  d_f_old = (float*) malloc(N * N * sizeof(float));
  memcpy(d_f_old, f_old, N * N * sizeof(float));

  d_error = (float*) malloc(sizeof(float));

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  const int max_iters = 10000;
  int num_iters = 0;

  #pragma omp target data use_device_addr(d_f, d_f_old, d_error)
  {
    auto start = std::chrono::steady_clock::now();

    while (error > tolerance && num_iters < max_iters) {
      *d_error = 0.0f;

      jacobi_step(d_f, d_f_old, d_error);

      std::swap(d_f, d_f_old);

      error = *d_error;
      error = sqrtf(error / (N * N));

      if (num_iters % 1000 == 0) {
        std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
      }

      ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    if (error <= tolerance && num_iters < max_iters) {
      std::cout << "PASS" << std::endl;
    }
    else {
      std::cout << "FAIL" << std::endl;
      return -1;
    }
  }

  free(d_f);
  free(d_f_old);
  free(d_error);
  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
